<?php
namespace App\Services\Compliance;
use App\Models\Compliance\GstExportLog; use App\Models\Crm\CrmInvoice; use App\Models\User; use Illuminate\Support\Collection;
class GstExportService { /** @return array{rows:Collection<int,array<string,mixed>>,warnings:array<int,string>} */ public function outward(User $u,?string $period):array{$invoices=CrmInvoice::query()->where('company_id',$u->company_id)->where('status','issued')->when($period,fn($q)=>$q->whereBetween('issue_date',[$period.'-01',now()->parse($period.'-01')->endOfMonth()->toDateString()]))->with('items')->limit(5000)->get();$warnings=[];$rows=$invoices->map(function($i)use(&$warnings){if(!$i->supplier_gstin_snapshot||!$i->place_of_supply_state_code)$warnings[]='Invoice '.$i->invoice_number.' is missing GST state data.';if($i->items->contains(fn($x)=>!$x->hsn_sac))$warnings[]='Invoice '.$i->invoice_number.' has missing HSN/SAC.';return ['invoice_number'=>$i->invoice_number,'issue_date'=>$i->issue_date?->toDateString(),'recipient_gstin'=>$i->customer_tax_number,'place_of_supply'=>$i->place_of_supply_state_code,'taxable_value'=>$i->taxable_total,'cgst'=>$i->cgst_total,'sgst'=>$i->sgst_total,'igst'=>$i->igst_total,'total'=>$i->grand_total,'currency'=>$i->currency];});return ['rows'=>$rows,'warnings'=>array_values(array_unique($warnings))];} public function log(User $u,string $type,?string $period,string $format,bool $draft,int $count,array $warnings):void{GstExportLog::create(['company_id'=>$u->company_id,'export_type'=>$type,'period'=>$period,'format'=>$format,'draft_export'=>$draft,'record_count'=>$count,'validation_summary'=>['warnings'=>$warnings],'generated_by'=>$u->id]);}}
